package com.promonts.dto;import com.promonts.domain.notice.Notice;import lombok.*;import java.time.LocalDateTime;@Data @NoArgsConstructor @AllArgsConstructor @Builder public class NoticeResponse{private Long id;private String title;private String content;private CourseInfo course;private AuthorInfo author;private LocalDateTime createdAt;@Data @AllArgsConstructor public static class CourseInfo{private Long id;private String name;private String code;}@Data @AllArgsConstructor public static class AuthorInfo{private Long id;private String name;private String email;}public static NoticeResponse from(Notice notice){CourseInfo courseInfo=new CourseInfo(notice.getCourse().getId(),notice.getCourse().getName(),notice.getCourse().getCode());AuthorInfo authorInfo=new AuthorInfo(notice.getAuthor().getId(),notice.getAuthor().getName(),notice.getAuthor().getEmail());return NoticeResponse.builder().id(notice.getId()).title(notice.getTitle()).content(notice.getContent()).course(courseInfo).author(authorInfo).createdAt(notice.getCreatedAt()).build();}}
